import { type GetTasks } from "wasp/server/operations";
import { type Task } from "wasp/entities";

export const getTasks: GetTasks = async (_args, context): Promise<Task[]> => {
  if (!context.user) {
    throw new Error("Not authenticated");
  }

  return context.entities.Task.findMany({
    where: { userId: context.user.id },
    orderBy: { id: "desc" },
  });
};

import { type GetTasks } from "wasp/server/operations";
import { type Task } from "wasp/entities";

export const getTasks: GetTasks = async (_args, context): Promise<Task[]> => {
  if (!context.user) {
    throw new Error("Not authenticated");
  }

  return context.entities.Task.findMany({
    where: { userId: context.user.id },
    orderBy: { id: "desc" },
  });
};

import { type CreateTask, type UpdateTask } from "wasp/server/operations";
import { type Task } from "wasp/entities";

export const createTask: CreateTask = async (
  { description },
  context
): Promise<Task> => {
  if (!context.user) {
    throw new Error("Not authenticated");
  }

  return context.entities.Task.create({
    data: {
      description,
      isDone: false,
      userId: context.user.id,
    },
  });
};

export const updateTask: UpdateTask = async (
  { taskId },
  context
): Promise<Task> => {
  if (!context.user) {
    throw new Error("Not authenticated");
  }

  const task = await context.entities.Task.findFirst({
    where: { id: taskId, userId: context.user.id },
  });

  if (!task) {
    throw new Error("Task not found");
  }

  return context.entities.Task.update({
    where: { id: taskId },
    data: { isDone: !task.isDone },
  });
};

