import { useState } from "react";
import { useAction, useQuery } from "wasp/client/operations";
import getTasks from "wasp/client/operations/getTasks";
import createTask from "wasp/client/operations/createTask";
import updateTask from "wasp/client/operations/updateTask";
import { logout } from "wasp/client/auth";
import "./Main.css";

export function MainPage() {
  const [description, setDescription] = useState("");
  const { data: tasks, isLoading, error } = useQuery(getTasks);
  const createTaskAction = useAction(createTask);
  const updateTaskAction = useAction(updateTask);

  const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    const trimmedDescription = description.trim();
    if (!trimmedDescription) {
      return;
    }

    await createTaskAction({ description: trimmedDescription });
    setDescription("");
  };

  return (
    <div className="page">
      <header className="page-header">
        <div>
          <h1>My Tasks</h1>
          <p className="subtitle">Stay on top of your personal todo list.</p>
        </div>
        <button className="button button-secondary" onClick={logout}>
          Logout
        </button>
      </header>

      <section className="card">
        <form className="task-form" onSubmit={handleSubmit}>
          <input
            type="text"
            value={description}
            placeholder="What do you need to do?"
            onChange={(event) => setDescription(event.target.value)}
          />
          <button className="button button-primary" type="submit">
            Add Task
          </button>
        </form>
      </section>

      <section className="card">
        <h2>Tasks</h2>
        {isLoading && <p className="muted">Loading tasks...</p>}
        {error && <p className="error">Failed to load tasks.</p>}
        {!isLoading && tasks?.length === 0 && (
          <p className="muted">No tasks yet. Add your first one above.</p>
        )}
        <ul className="task-list">
          {tasks?.map((task) => (
            <li key={task.id} className="task-item">
              <label className={`task-label ${task.isDone ? "done" : ""}`}>
                <input
                  type="checkbox"
                  checked={task.isDone}
                  onChange={() => updateTaskAction({ taskId: task.id })}
                />
                <span>{task.description}</span>
              </label>
            </li>
          ))}
        </ul>
      </section>
    </div>
  );
}

