* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: "Inter", "Segoe UI", system-ui, -apple-system, sans-serif;
  background: #f3f5f9;
  color: #1f2933;
}

#root {
  min-height: 100vh;
  display: flex;
  justify-content: center;
  align-items: flex-start;
  padding: 48px 16px;
}

.page {
  width: 100%;
  max-width: 760px;
  display: flex;
  flex-direction: column;
  gap: 24px;
}

.page-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 16px;
}

.subtitle {
  color: #52606d;
  margin-top: 6px;
}

.card {
  background: #ffffff;
  border-radius: 16px;
  padding: 24px;
  box-shadow: 0 14px 30px rgba(15, 23, 42, 0.08);
}

.task-form {
  display: flex;
  gap: 12px;
}

.task-form input {
  flex: 1;
  padding: 12px 14px;
  border-radius: 10px;
  border: 1px solid #d7dce5;
  font-size: 1rem;
}

.task-form input:focus {
  outline: none;
  border-color: #4c6ef5;
  box-shadow: 0 0 0 3px rgba(76, 110, 245, 0.15);
}

.button {
  border: none;
  border-radius: 10px;
  padding: 12px 18px;
  font-weight: 600;
  cursor: pointer;
  transition: transform 0.15s ease, box-shadow 0.15s ease;
}

.button-primary {
  background: #4c6ef5;
  color: #ffffff;
  box-shadow: 0 10px 18px rgba(76, 110, 245, 0.25);
}

.button-secondary {
  background: #ffffff;
  color: #1f2933;
  border: 1px solid #d7dce5;
}

.button:hover {
  transform: translateY(-1px);
}

.task-list {
  list-style: none;
  margin-top: 16px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.task-item {
  display: flex;
}

.task-label {
  display: flex;
  align-items: center;
  gap: 10px;
  font-weight: 500;
}

.task-label input {
  width: 18px;
  height: 18px;
}

.task-label.done span {
  text-decoration: line-through;
  color: #9aa5b1;
}

.muted {
  color: #7b8794;
  margin-top: 12px;
}

.error {
  color: #d64545;
  margin-top: 12px;
}

.auth-page {
  width: 100%;
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 32px 16px;
}

.auth-card {
  width: 100%;
  max-width: 420px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

a {
  color: #4c6ef5;
  text-decoration: none;
}

a:hover {
  text-decoration: underline;
}

